// // This module implements a 5-bit Johnson counter with asynchronous reset. The counter shifts its value to the left and inverts the rightmost bit on every negative clock edge. If reset is low, the counter should reset to 1.
module johnson_counter(
	input clk,
	input reset,
	output reg [4:0] count);always @(posedge clk) begin
    if (reset)
        count <= 5'b00000;
    else
        count <= {~count[0], count[4:1]};
end
endmodule
